  function createRef() {
    return {
      flag: false,
      pending: false,
      animations: [],
      characters: [],
      scene: null,
      camera: null,
      renderer: null,
      avatar: null,
      speed: 0.1,
      pauseMs: 800,
      animationFrameId: null,
    };
  }

  function applyDefaultPose(ref) {
    ref.animations = [];
    ref.characters.push(" ");
    ref.animations.push(DEFAULT_POSE_HOLD.map(function (r) { return r.slice(); }));
    ref.animations.push([]);
    if (!ref.pending) {
      ref.pending = true;
      ref.animate();
    }
  }

  function attachAnimate(ref) {
    ref.animate = function () {
      if (ref.animations.length === 0) {
        ref.pending = false;
        return;
      }
      ref.animationFrameId = requestAnimationFrame(ref.animate);
      if (ref.animations[0].length) {
        if (!ref.flag) {
          for (var i = 0; i < ref.animations[0].length; ) {
            var row = ref.animations[0][i];
            var boneName = row[0];
            var action = row[1];
            var axis = row[2];
            var limit = row[3];
            var sign = row[4];
            var bone = ref.avatar.getObjectByName(boneName);
            if (!bone) {
              ref.animations[0].splice(i, 1);
              continue;
            }
            var cur = bone[action][axis];
            if (sign === "+" && cur < limit) {
              bone[action][axis] = Math.min(cur + ref.speed, limit);
              i++;
            } else if (sign === "-" && cur > limit) {
              bone[action][axis] = Math.max(cur - ref.speed, limit);
              i++;
            } else {
              ref.animations[0].splice(i, 1);
            }
          }
        }
      } else {
        ref.flag = true;
        setTimeout(function () {
          ref.flag = false;
        }, ref.pauseMs);
        ref.animations.shift();
      }
      ref.renderer.render(ref.scene, ref.camera);
    };
  }

  function loadCharacter(canvasId, options) {
    options = options || {};
    var THREE = global.THREE;
    if (!THREE) throw new Error("THREE not loaded");

    var modelUrl = options.modelUrl || "models/ybot.glb";
    var container = document.getElementById(canvasId);
    if (!container) throw new Error("Element #" + canvasId + " not found");

    var ref = createRef();
    ref.speed = options.speed != null ? options.speed : 0.1;
    ref.pauseMs = options.pauseMs != null ? options.pauseMs : 800;

    ref.scene = new THREE.Scene();
    ref.scene.background = new THREE.Color(0xdddddd);

    var spotLight = new THREE.SpotLight(0xffffff, 2);
    spotLight.position.set(0, 5, 5);
    ref.scene.add(spotLight);

    var w = container.clientWidth || global.innerWidth * 0.57;
    var h = container.clientHeight || global.innerHeight - 70;
    ref.camera = new THREE.PerspectiveCamera(30, w / h, 0.1, 1000);
    ref.renderer = new THREE.WebGLRenderer({ antialias: true });
    ref.renderer.setSize(w, h);
    ref.renderer.setPixelRatio(global.devicePixelRatio || 1);
    container.innerHTML = "";
    container.appendChild(ref.renderer.domElement);

    ref.camera.position.z = 1.6;
    ref.camera.position.y = 1.4;

    var GLTFLoaderClass = THREE.GLTFLoader || global.GLTFLoader;
    if (!GLTFLoaderClass) {
      throw new Error("GLTFLoader not found. Load GLTFLoader before signing-core.js (see signing-portable/index.html).");
    }
    var loader = new GLTFLoaderClass();
    loader.load(
      modelUrl,
      function (gltf) {
        gltf.scene.traverse(function (child) {
          if (child.type === "SkinnedMesh") child.frustumCulled = false;
        });
        ref.avatar = gltf.scene;
        ref.scene.add(ref.avatar);
        attachAnimate(ref);
        applyDefaultPose(ref);
      },
      undefined,
      function (err) {
        console.error(err);
      }
    );

    global.addEventListener("resize", function () {
      var cw = container.clientWidth || global.innerWidth * 0.57;
      var ch = container.clientHeight || global.innerHeight - 70;
      ref.camera.aspect = cw / ch;
      ref.camera.updateProjectionMatrix();
      ref.renderer.setSize(cw, ch);
    });

    return ref;
  }

  function playSign(ref, letter) {
    var L = String(letter).toUpperCase();
    if (!SIGN_POSES[L]) {
      console.warn("No pose for letter:", L);
      return;
    }
    var frames = SIGN_POSES[L];
    ref.animations.push(frames[0].map(function (r) { return r.slice(); }));
    ref.animations.push(frames[1].map(function (r) { return r.slice(); }));
    if (ref.pending === false) {
      ref.pending = true;
      ref.animate();
    }
  }

  function estimateLetterMs(ref, letter) {
    var frames = SIGN_POSES[letter];
    if (!frames || !ref.avatar) return 600;
    var maxSteps = 0;
    [frames[0], frames[1]].forEach(function (frame) {
      frame.forEach(function (row) {
        var bone = ref.avatar.getObjectByName(row[0]);
        if (!bone) return;
        var cur = bone[row[1]][row[2]];
        var limit = row[3];
        var diff = Math.abs(limit - cur);
        var steps = diff / (ref.speed || 0.1);
        if (steps > maxSteps) maxSteps = steps;
      });
    });
    return (maxSteps / 60) * 1000;
  }

  function playText(ref, text, onLetter) {
    var s = String(text).toUpperCase().replace(/[^A-Z]/g, "");
    var i = 0;
    function step() {
      if (i >= s.length) {
        if (typeof onLetter === "function") onLetter(null);
        return;
      }
      var ch = s[i++];
      if (typeof onLetter === "function") onLetter(ch);
      playSign(ref, ch);
      var delay = estimateLetterMs(ref, ch) + ref.pauseMs + 150;
      setTimeout(step, delay);
    }
    if (s.length) step();
    else if (typeof onLetter === "function") onLetter(null);
  }

  global.SigningCore = {
    SIGN_POSES: SIGN_POSES,
    DEFAULT_POSE_HOLD: DEFAULT_POSE_HOLD,
    loadCharacter: loadCharacter,
    playSign: playSign,
    playText: playText,
    applyDefaultPose: applyDefaultPose,
  };
